/* --- 全局修正：约束右侧“角色/世界信息”面板宽度与位置 --- */

/* 1. 【核心】为右侧面板设定固定的、合理的最大宽度和位置 */
#right-nav-panel.drawer-content {
    max-width: 500px !important; /* 您可以微调这个数值，500px 是一个比较舒适的宽度 */
    min-width: 420px !important;
    width: 35vw !important;      /* 使用视口宽度的35% */

    right: 0 !important;
    left: auto !important; /* 确保 left 定位无效 */
    transform: none !important; /* 移除任何可能导致偏移的 transform */

    /* 确保内部内容可以滚动 */
    overflow-x: hidden !important; 
    overflow-y: auto !important;
}

/* 2. 确保面板内的主要内容区域能正确工作 */
#right-nav-panel #rm_characters_block,
#right-nav-panel #rm_ch_create_block,
#right-nav-panel #rm_group_chats_block,
#WorldInfo {
    width: 100% !important;
    box-sizing: border-box; /* 确保 padding 不会增加宽度 */
}

/* 3. 特别针对“世界信息”(#WorldInfo) 内部的布局进行保护 */
#wi-holder {
    width: 100% !important;
    box-sizing: border-box;
    padding: 10px; /* 给予一些内部呼吸空间 */
}

/* 4. 确保世界信息条目列表不会溢出 */
#world_popup_entries_list {
    width: 100% !important;
    box-sizing: border-box;
}

/* 5. (可选，但推荐) 修正面板内其他可能被拉伸的输入框和下拉菜单 */
#right-nav-panel .text_pole,
#right-nav-panel textarea,
#right-nav-panel select {
    width: 100% !important;
    box-sizing: border-box;
}
